  const tasksRaw = await callGateway(taskPrompt, 8000);
  let taskList: any[] = [];
  try {
    const parsed = JSON.parse(tasksRaw.replace(/```json|```/g, '').trim());
    taskList = Array.isArray(parsed) ? parsed : parsed.tasks || [];
